const char* const Filtered_kernel___class__ = "Filtered_kernel is a kernel that uses a filtering technique based on interval arithmetic form to achieve exact and efficient predicates. It is based on [1] . In addition, a few selected important predicates are implemented using the formally proved, semi-static, filtering techniques from [4] . The geometric constructions are exactly those of the kernel CK , which means that they are not necessarily exact. CK the \"Construction Kernel\", namely the kernel from which are taken the types of the geometric objects as well as the geometric constructions. UseStaticFilters a Boolean value which activates or not an additional layer of semi-static filters. It defaults to true (activated), unless the CGAL_NO_STATIC_FILTERS macro is defined. This option is mostly for debugging and testing, there should be no production use for deactivating static filters. Is model of Kernel Example The following example shows how to produce a kernel whose geometric objects and constructions are those of Simple_cartesian <double> but the predicates are exact. #include <CGAL/Simple_cartesian.h> #include <CGAL/Filtered_kernel.h> typedef CGAL::Simple_cartesian<double> CK; typedef CGAL::Filtered_kernel<CK> K; Implementation The implementation uses CGAL::Filtered_predicate <EP, FP, C2E, C2F> over each predicate of the kernel traits interface. Additionally, faster static filters may be used for a few selected critical predicates.";
const char* const Filtered_kernel_Exact_kernel = "The type of the exact kernel. Returns: EK";
const char* const Filtered_kernel_Approximate_kernel = "The type of the approximate \"filtering\" kernel. Returns: FK";
const char* const Filtered_kernel_Has_static_filters = "A Boolean value corresponding to the second template argument. Returns: const bool";
const char* const Filtered_kernel_adaptor___class__ = "Filtered_kernel_adaptor is a kernel that uses a filtering technique to obtain a kernel with exact and efficient predicate functors. The geometric constructions are exactly those of the kernel CK , which means that they are not necessarily exact. More details about the filtering technique can be found in [1] . In contrast to Filtered_kernel , the global functions are those of CK . Is model of Kernel Example The following example shows how to produce a kernel whose geometric objects and constructions are those of Simple_cartesian <double> The predicate functors of the kernel are exact, the global functions are not. #include <CGAL/Simple_cartesian.h> #include <CGAL/Filtered_kernel.h> typedef CGAL::Simple_cartesian<double> CK; typedef CGAL::Filtered_kernel_adaptor<CK> K; typedef K::Point_2 p(0,0), q(1,1), r(1,5); CGAL::orientation (p,q,r); // not exact typedef K::Orientation_2 orientation ; orientation (p,q,r); // exact";
const char* const Filtered_predicate___class__ = "Filtered_predicate is an adaptor for predicate function objects that allows one to produce efficient and exact predicates. It is used to build CGAL::Filtered_kernel <CK> and can be used for other predicates too. EP is the exact but supposedly slow predicate that is able to evaluate the predicate correctly. It will be called only when the filtering predicate, FP , cannot compute the correct result. This failure of FP must be done by throwing an exception. To convert the geometric objects that are the arguments of the predicate, we use the function objects C2E and C2F , which must be of the form Cartesian_converter or Homogeneous_converter . Example The following example defines an efficient and exact version of the orientation predicate over three points using the Cartesian representation with double coordinates and without reference counting ( Simple_cartesian::Point_2 ). Of course, the orientation predicate can already be found in the kernel, but you can follow this example to filter your own predicates. It uses the fast but inexact predicate based on interval arithmetic for filtering and the slow but exact predicate based on multi-precision floats when the filtering predicate fails. Example: Filtered_kernel/Filtered_predicate.cpp Show / Hide #include <CGAL/Simple_cartesian.h> #include <CGAL/Filtered_predicate.h> #include <CGAL/MP_Float.h> #include <CGAL/Cartesian_converter.h> typedef CGAL::Simple_cartesian<double> K; typedef CGAL::Simple_cartesian<CGAL::Interval_nt_advanced> FK; typedef CGAL::Simple_cartesian<CGAL::MP_Float> EK; typedef CGAL::Cartesian_converter<K, EK> C2E; typedef CGAL::Cartesian_converter<K, FK> C2F; // Define my predicate, parameterized by a kernel. template < typename K > struct My_orientation_2 { typedef typename K::RT RT; typedef typename K::Point_2 Point_2; typedef typename K::Orientation Orientation ; Orientation operator()( const Point_2 &p, const Point_2 &q, const Point_2 &r) const { RT prx = p.x() - r.x(); RT pry = p.y() - r.y(); RT qrx = q.x() - r.x(); RT qry = q.y() - r.y(); return CGAL::sign( prx*qry - qrx*pry ); } }; typedef CGAL::Filtered_predicate<My_orientation_2<EK> , My_orientation_2<FK>, C2E, C2F> Orientation_2; int main() { K::Point_2 p(1,2), q(2,3), r(3,4); Orientation_2 orientation ; orientation (p, q, r); return 0; }";
const char* const Filtered_predicate_result_type = "The return type of the function operators. Returns: FP::result_type";
const char* const Filtered_predicate_Filtered_predicate = "Default constructor.";
const char* const Filtered_predicate_operator = "The function operator for predicates. Returns: result_type";
const char* const Homogeneous___class__ = "A model for a Kernel using homogeneous coordinates to represent the geometric objects. In order for Homogeneous to model Euclidean geometry in $ E^2$ and/or $ E^3$ , for some mathematical ring $ E$ ( e.g. , the integers $\\mathbb{Z}$ or the rationals $\\mathbb{Q}$ ), the template parameter RingNumberType must model the mathematical ring $ E$ . That is, the ring operations on this number type must compute the mathematically correct results. If the number type provided as a model for RingNumberType is only an approximation of a ring (such as the built-in type double ), then the geometry provided by the kernel is only an approximation of Euclidean geometry. Is model of Kernel Implementation This model of a kernel uses reference counting. CGAL::Cartesian <FieldNumberType> CGAL::Simple_cartesian <FieldNumberType> CGAL::Simple_homogeneous <RingNumberType>";
const char* const Homogeneous_FT = "Returns: Quotient< RingNumberType >";
const char* const Homogeneous_RT = "Returns: RingNumberType";
const char* const Homogeneous_converter___class__ = "Homogeneous_converter converts objects from the kernel traits K1 to the kernel traits K2 . Those traits must be of the form Homogeneous <RT1> and Homogeneous <RT2> (or the equivalent with Simple_homogeneous ). It then provides the following operators to convert objects from K1 to K2 . The third template parameter RTConverter is a function object that must provide K2::RT operator()(const K1::RT &n); that converts n to an K2::RT that has the same value. The default value of this parameter is CGAL::NT_converter<K1::RT, K2::RT> , which uses the conversion operator from K1::RT to K2::RT . Similarly, the fourth template parameter must provide K2::FT operator()(const K1::FT &n); that converts n to an K2::FT that has the same value. Its default value is CGAL::NT_converter<K1::FT, K2::FT> . CGAL::Homogeneous <RingNumberType> CGAL::Simple_homogeneous <RingNumberType>";
const char* const Homogeneous_converter_Homogeneous_converter = "Default constructor.";
const char* const Homogeneous_converter_operator = "returns a K2::Point_2 which coordinates are those of p , converted by RTConverter . Returns: K2::Point_2";
